llm_verdict.message:
[
  {
    "operation": "read_file",
    "args": {
      "path": "/etc/systemd/system/usbguard.service"
    },
    "description": "Check if USBGuard service unit file exists to verify service presence."
  },
  {
    "operation": "run_cmd",
    "args": {
      "command": "usbguard generate-policy > /etc/usbguard/rules.conf"
    },
    "description": "Generate initial USBGuard policy based on currently attached USB devices."
  },
  {
    "operation": "run_cmd",
    "args": {
      "command": "systemctl unmask usbguard.service"
    },
    "description": "Unmask the USBGuard service to allow it to be started."
  },
  {
    "operation": "run_cmd",
    "args": {
      "command": "systemctl enable usbguard.service"
    },
    "description": "Enable and start the USBGuard service."
  }
]

